      null,
      null,
      '{}'::jsonb,
      0.52,
      'imported',
      '{"features": [], "osm_id": 9337735619, "osm_type": "node", "source": "osm", "tags": {"brand": "Toyota", "brand:wikidata": "Q53268", "brand:wikipedia": "es:Toyota", "name": "Medimotors Premium", "service:vehicle:car_repair": "yes", "shop": "car"}}'::jsonb
